using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // --- FormatPhoneNumber ---

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        string result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.StartsWith(result, "(800)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        string result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDashSeparator()
    {
        string result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsExpectedFormat()
    {
        string result = _formatter.FormatPhoneNumber("8005551234");

        Assert.AreEqual("(800) 555-1234", result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        _formatter.FormatPhoneNumber(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException()
    {
        _formatter.FormatPhoneNumber("123");
    }

    // --- BuildGreeting ---

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_StartsWithDearMr()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_EndsWithComma()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_StartsWithDearAndTitle()
    {
        string result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
    }

    [TestMethod]
    public void BuildGreeting_WithName_ContainsName()
    {
        string result = _formatter.BuildGreeting("Smith", "Ms.");

        StringAssert.Contains(result, "Smith");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException()
    {
        _formatter.BuildGreeting("   ");
    }

    // --- GenerateSlug ---

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseWithDashes()
    {
        string result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_DoesNotStartWithDash()
    {
        string result = _formatter.GenerateSlug("  --My Post!  ");

        Assert.IsFalse(result.StartsWith("-"));
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_DoesNotEndWithDash()
    {
        string result = _formatter.GenerateSlug("My Post!!!");

        Assert.IsFalse(result.EndsWith("-"));
    }

    [TestMethod]
    public void GenerateSlug_TitleWithMultipleSpaces_ContainsSingleDashes()
    {
        string result = _formatter.GenerateSlug("Hello   Beautiful   World");

        StringAssert.Contains(result, "hello-beautiful-world");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_WhitespaceTitle_ThrowsArgumentException()
    {
        _formatter.GenerateSlug("   ");
    }

    // --- FormatCurrency ---

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        string result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        string result = _formatter.FormatCurrency(19.99m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        string result = _formatter.FormatCurrency(100m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        string result = _formatter.FormatCurrency(-5.50m);

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatCurrency_PreciseAmount_ReturnsExpectedFormat()
    {
        string result = _formatter.FormatCurrency(1234.56m, "£");

        Assert.AreEqual("£1234.56", result);
    }
}

